        ];

        // Base query with join to categories
        $baseQuery = "
            FROM products p
            LEFT JOIN categories c ON p.category_id = c.id
        ";

        // Always filter active products
        $conditions[] = "p.is_active = 1";

        // Name search using LIKE with relevance scoring
        if (!empty($name)) {
            $searchTerm = trim($name);

            // Add relevance score for sorting
            $selectFields[] = DB::raw("
                (
                    CASE
                        WHEN p.name = ? THEN 100
                        WHEN p.name LIKE ? THEN 75
                        WHEN p.name LIKE ? THEN 50
                        WHEN p.name LIKE ? THEN 25
                        WHEN p.description LIKE ? THEN 10
                        ELSE 0
                    END
                ) AS relevance_score
            ")->getValue(DB::connection()->getQueryGrammar());

            // Bindings for the relevance CASE statement
            $bindings[] = $searchTerm;                    // exact match
            $bindings[] = $searchTerm . '%';              // starts with
            $bindings[] = '%' . $searchTerm . '%';        // contains in name
            $bindings[] = '% ' . $searchTerm . ' %';     // word match
            $bindings[] = '%' . $searchTerm . '%';        // contains in description

            // Filter: must match name or description
            $conditions[] = "(p.name LIKE ? OR p.description LIKE ?)";
            $bindings[] = '%' . $searchTerm . '%';
            $bindings[] = '%' . $searchTerm . '%';
        } else {
            $selectFields[] = DB::raw("0 AS relevance_score")->getValue(DB::connection()->getQueryGrammar());
        }

        // Category filter by name
        if (!empty($category)) {
            $conditions[] = "c.name LIKE ?";
            $bindings[] = '%' . trim($category) . '%';
        }

        // Category filter by ID
        if (!empty($categoryId)) {
            $conditions[] = "p.category_id = ?";
            $bindings[] = $categoryId;
        }

        // Price range filter
        if ($minPrice !== null) {
            $conditions[] = "p.price >= ?";
