            $bindings[] = $maxPrice;
        }

        // Build WHERE clause
        $whereClause = '';
        if (!empty($conditions)) {
            $whereClause = 'WHERE ' . implode(' AND ', $conditions);
        }

        // Build ORDER BY clause
        $orderByClause = match ($sortBy) {
