            default      => "ORDER BY relevance_score DESC, p.created_at DESC",
        };

        // Build the select fields string
        $selectString = implode(', ', $selectFields);

        // Count query for pagination
        $countSql = "SELECT COUNT(*) AS total {$baseQuery} {$whereClause}";
        // For count, we only need the WHERE bindings (not the relevance CASE bindings)
        // We need to separate bindings for count vs select
        $countBindings = [];
        $countConditions = [];
        $countIdx = 0;

        // Rebuild count bindings (skip the relevance CASE bindings)
        if (!empty($name)) {
            $searchTerm = trim($name);
            $countConditions[] = "p.is_active = 1";
            $countConditions[] = "(p.name LIKE ? OR p.description LIKE ?)";
            $countBindings[] = '%' . $searchTerm . '%';
