        } else {
            $countConditions[] = "p.is_active = 1";
        }

        if (!empty($category)) {
            $countConditions[] = "c.name LIKE ?";
            $countBindings[] = '%' . trim($category) . '%';
        }

        if (!empty($categoryId)) {
            $countConditions[] = "p.category_id = ?";
            $countBindings[] = $categoryId;
        }

        if ($minPrice !== null) {
            $countConditions[] = "p.price >= ?";
            $countBindings[] = $minPrice;
        }

        if ($maxPrice !== null) {
            $countConditions[] = "p.price <= ?";
            $countBindings[] = $maxPrice;
        }

        $countWhereClause = '';
        if (!empty($countConditions)) {
            $countWhereClause = 'WHERE ' . implode(' AND ', $countConditions);
        }

        $countSql = "SELECT COUNT(*) AS total {$baseQuery} {$countWhereClause}";
        $totalCount = DB::selectOne(DB::raw($countSql), $countBindings)->total;

        // Calculate pagination
        $page = max(1, (int) $request->input('page', 1));
        $offset = ($page - 1) * $perPage;
        $lastPage = (int) ceil($totalCount / $perPage);

        // Main data query with LIMIT/OFFSET
        $dataSql = "
            SELECT {$selectString}
            {$baseQuery}
            {$whereClause}
            {$orderByClause}
            LIMIT ? OFFSET ?
        ";

        $bindings[] = (int) $perPage;
        $bindings[] = (int) $offset;

        $products = DB::select(DB::raw($dataSql), $bindings);

        // Get aggregation data for filters (price range and category counts)
        $aggregationSql = "
            SELECT
                MIN(p.price) AS min_price,
